// normalise source CRM contact fields
const src = $input.item.json;
return [{
  json: {
    contactId: src.id || src.vid || src.contactId || '',
    email: src.email || src.properties?.email?.value || '',
    firstName: src.firstName || src.properties?.firstname?.value || '',
    lastName: src.lastName || src.properties?.lastname?.value || '',
    phone: src.phone || src.properties?.phone?.value || '',
    company: src.company || src.properties?.company?.value || '',
    updatedAt: src.updatedAt || src.properties?.lastmodifieddate || new Date().toISOString()
  }
}];

const item = $input.item.json;
let exists = false;
let personId = null;
if (item.data && item.data.items && item.data.items.length > 0) {
  exists = true;
  personId = item.data.items[0].item.id;
}
return [{
  json: {
    ...item,
    exists,
    personId
  }
}];

const { email, firstName, lastName, notificationType } = $input.item.json;
return [{
  json: {
    email,
    firstName,
    lastName,
    tag: notificationType === 'new' ? 'New' : 'Updated'
  }
}];
